export enum Severity {
  OPERATIONAL = 'OPERATIONAL',
  DEGRADED = 'DEGRADED',
  OUTAGE = 'OUTAGE'
}

export interface Region {
  id: string;
  name: string;
}

export interface Service {
  id: string;
  regionId: string;
  name: string;
  description: string;
}

export interface Component {
  id: string;
