                          <button onClick={() => { if(confirm('Delete template?')) removeTemplate(t.id); }} className="text-red-500 hover:underline text-xs font-bold uppercase">Delete</button>
                        </td>
                      </tr>
                    ))}
                    {state.templates.length === 0 && (
