/**
 * SECURITY HELPERS
 */
const hashPassword = (password) => {
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.scryptSync(password, salt, 64).toString('hex');
  return `${salt}:${hash}`;
};

const verifyPassword = (password, storedValue) => {
  try {
    if (!storedValue || !storedValue.includes(':')) return false;
    const [salt, hash] = storedValue.split(':');
    const derivedHash = crypto.scryptSync(password, salt, 64).toString('hex');
    return derivedHash === hash;
  } catch (e) {
    return false;
  }
};

/**
 * AUTHENTICATION MIDDLEWARE
 */
const sessions = new Map();

const authenticate = (req, res, next) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  const token = authHeader.split(' ')[1];
  const username = sessions.get(token);
  if (!username) {
    return res.status(401).json({ error: 'Session expired' });
  }
  req.user = username;
  next();
};

const pool = new Pool({
  connectionString: process.env.DATABASE_URL || 'postgresql://postgres:postgres@localhost:5432/voximplant_status',
});

/**
 * NOTIFICATION HELPERS (Mailchimp)
 */
async function notifySubscribers(incidentId, type) {
  try {
    const subscribersRes = await pool.query('SELECT email FROM subscriptions');
    const subscribers = subscribersRes.rows;
    if (subscribers.length === 0) return;

    const incidentRes = await pool.query(`
      SELECT i.*, c.name as comp_name, s.name as svc_name, r.name as reg_name
      FROM incidents i
      JOIN components c ON i.component_id = c.id
      JOIN services s ON c.service_id = s.id
      JOIN regions r ON s.region_id = r.id
      WHERE i.id = $1
    `, [incidentId]);

    if (incidentRes.rows.length === 0) return;
    const incident = incidentRes.rows[0];

    const templateKey = type === 'NEW' ? 'incident_new_template' : 'incident_resolved_template';
    const templateRes = await pool.query('SELECT value FROM notification_settings WHERE key = $1', [templateKey]);
    let message = templateRes.rows[0]?.value || 'Update on Voximplant Status.';

    // Placeholder replacement
    message = message
      .replace(/{title}/g, incident.title)
      .replace(/{component}/g, incident.comp_name)
      .replace(/{service}/g, incident.svc_name)
      .replace(/{region}/g, incident.reg_name)
      .replace(/{severity}/g, incident.severity);

    console.log(`[NOTIFY] Sending to ${subscribers.length} subscribers: ${message}`);

    // Mock Mailchimp Transactional Call
    // In a real environment, you'd use fetch() to https://<dc>.api.mailchimp.com/3.0/
    if (process.env.MAILCHIMP_API_KEY) {
      // Logic for sending emails goes here.
      // We would iterate through subscribers and use Mailchimp's Transactional (Mandrill) API
      // to avoid list management complexities for system alerts.
    }
  } catch (err) {
    console.error('[NOTIFY ERROR]', err);
  }
}

