import 'dotenv/config';
import express from 'express';
import pg from 'pg';
const { Pool } = pg;
import crypto from 'crypto';
import fs from 'fs';
import path from 'path';
import * as esbuild from 'esbuild';

const app = express();
const rootPath = path.resolve();

app.use(express.json());

/**
 * SECURITY HELPERS
 */
const hashPassword = (password) => {
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.scryptSync(password, salt, 64).toString('hex');
  return `${salt}:${hash}`;
};

const verifyPassword = (password, storedValue) => {
  try {
    if (!storedValue || !storedValue.includes(':')) return false;
    const [salt, hash] = storedValue.split(':');
    const derivedHash = crypto.scryptSync(password, salt, 64).toString('hex');
    return derivedHash === hash;
  } catch (e) {
    return false;
  }
};

/**
 * AUTHENTICATION MIDDLEWARE
 */
const sessions = new Map();

const authenticate = (req, res, next) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  const token = authHeader.split(' ')[1];
  const username = sessions.get(token);
  if (!username) {
    return res.status(401).json({ error: 'Session expired' });
  }
  req.user = username;
  next();
};

const pool = new Pool({
  connectionString: process.env.DATABASE_URL || 'postgresql://postgres:postgres@localhost:5432/voximplant_status',
});

/**
 * NOTIFICATION HELPERS (Mailchimp Transactional / Mandrill)
 */
async function notifySubscribers(incidentId, type) {
  const apiKey = process.env.MAILCHIMP_API_KEY;
  if (!apiKey) {
    console.log('[NOTIFY] Mailchimp API Key missing. Skipping real emails.');
    return;
  }

  try {
    const subscribersRes = await pool.query('SELECT email FROM subscriptions');
    const subscribers = subscribersRes.rows;
    if (subscribers.length === 0) return;

    const incidentRes = await pool.query(`
      SELECT i.*, c.name as comp_name, s.name as svc_name, r.name as reg_name
      FROM incidents i
      JOIN components c ON i.component_id = c.id
      JOIN services s ON c.service_id = s.id
      JOIN regions r ON s.region_id = r.id
      WHERE i.id = $1
    `, [incidentId]);

    if (incidentRes.rows.length === 0) return;
    const incident = incidentRes.rows[0];

    const templateKey = type === 'NEW' ? 'incident_new_template' : 'incident_resolved_template';
    const templateRes = await pool.query('SELECT value FROM notification_settings WHERE key = $1', [templateKey]);
    let messageHtml = templateRes.rows[0]?.value || 'Update on Voximplant Status.';

    // Placeholder replacement
    const placeholders = {
      '{title}': incident.title,
      '{component}': incident.comp_name,
      '{service}': incident.svc_name,
      '{region}': incident.reg_name,
      '{severity}': incident.severity
    };

    Object.entries(placeholders).forEach(([key, val]) => {
      const regex = new RegExp(key, 'g');
      messageHtml = messageHtml.replace(regex, val || '');
    });

    const subject = type === 'NEW' ? `[Issue] ${incident.title}` : `[Resolved] ${incident.title}`;

    console.log(`[NOTIFY] Dispatching to ${subscribers.length} subscribers via Mailchimp`);

    // Mailchimp Transactional (Mandrill) API call
    const response = await fetch('https://mandrillapp.com/api/1.0/messages/send.json', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        key: apiKey,
        message: {
          from_email: process.env.MAILCHIMP_FROM_EMAIL || 'status@voximplant.com',
          from_name: 'Voximplant Status',
          subject: subject,
          html: `<div style="font-family: sans-serif; padding: 20px;">${messageHtml.replace(/\n/g, '<br>')}</div>`,
          to: subscribers.map(s => ({ email: s.email, type: 'to' }))
        }
      })
    });

    const result = await response.json();
    console.log('[NOTIFY] Mailchimp Response:', result);

  } catch (err) {
    console.error('[NOTIFY ERROR]', err);
  }
}

