    res.json({
      regions: regions.rows,
      services: services.rows,
      components: components.rows,
      incidents: incidents.rows,
      templates: templates.rows,
      notificationSettings: notifySettings
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

