import React, { useState } from 'react';
import { useApp } from '../store.tsx';
import { Severity, Incident } from '../types.ts';
import UptimeGraph from './UptimeGraph.tsx';

const PublicDashboard: React.FC = () => {
  const { state, calculateSLA, subscribe, unsubscribe } = useApp();
  const [email, setEmail] = useState('');
  const [subStatus, setSubStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');

  const formatDate = (dateStr: string | null | undefined) => {
    if (!dateStr) return 'N/A';
    try {
      const d = new Date(dateStr);
      if (isNaN(d.getTime())) return 'Invalid Date';
      const utc = d.getTime() + (d.getTimezoneOffset() * 60000);
      const adjustedDate = new Date(utc + (state.timezoneOffset * 60000));
      return adjustedDate.toLocaleString(undefined, {
        month: 'short',
        day: 'numeric',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch (e) {
      return 'Error Parsing Date';
    }
  };

  const formatSimpleDate = (dateStr: string) => {
    const d = new Date(dateStr);
    const utc = d.getTime() + (d.getTimezoneOffset() * 60000);
    const adjustedDate = new Date(utc + (state.timezoneOffset * 60000));
    return adjustedDate.toLocaleDateString(undefined, {
      month: 'long',
      day: 'numeric',
      year: 'numeric'
    });
  };

  const handleSubscribe = async (e: React.FormEvent, isUnsubscribe = false) => {
    e.preventDefault();
    if (!email) return;
    setSubStatus('loading');
    setErrorMessage('');
    try {
      if (isUnsubscribe) {
        await unsubscribe(email);
        setSubStatus('success');
        setErrorMessage('You have been successfully unsubscribed.');
      } else {
        await subscribe(email);
        setSubStatus('success');
      }
      setEmail('');
    } catch (err: any) {
      setSubStatus('error');
      setErrorMessage(err.message || 'Subscription failed.');
    }
  };

  const getComponentStatus = (componentId: string) => {
    const activeIncidents = state.incidents.filter(i => i.componentId === componentId && !i.endTime);
    if (activeIncidents.find(i => i.severity === Severity.OUTAGE)) return Severity.OUTAGE;
    if (activeIncidents.find(i => i.severity === Severity.DEGRADED)) return Severity.DEGRADED;
    return Severity.OPERATIONAL;
  };

  const getServiceStatus = (serviceId: string) => {
    const componentIds = state.components.filter(c => c.serviceId === serviceId).map(c => c.id);
    if (componentIds.length === 0) return Severity.OPERATIONAL;
    const statuses = componentIds.map(getComponentStatus);
    if (statuses.includes(Severity.OUTAGE)) return Severity.OUTAGE;
    if (statuses.includes(Severity.DEGRADED)) return Severity.DEGRADED;
    return Severity.OPERATIONAL;
  };

  const globalStatus = React.useMemo(() => {
    if (state.components.length === 0) return { label: 'System Initializing', color: 'bg-indigo-500', sub: 'Monitoring is starting up...' };
    const statuses = state.components.map(c => getComponentStatus(c.id));
    if (statuses.includes(Severity.OUTAGE)) return { label: 'System Outage', color: 'bg-red-600', sub: 'Major disruptions are occurring' };
    if (statuses.includes(Severity.DEGRADED)) return { label: 'Partial Degradation', color: 'bg-yellow-500', sub: 'Some services are experiencing issues' };
    return { label: 'All Systems Operational', color: 'bg-emerald-500', sub: 'Services are running optimally' };
  }, [state, state.incidents, state.components]);

  const pastIncidentsByDate = React.useMemo(() => {
    const ninetyDaysAgo = new Date();
    ninetyDaysAgo.setDate(ninetyDaysAgo.getDate() - 90);

    const filtered = state.incidents
      .filter(i => new Date(i.startTime) >= ninetyDaysAgo)
      .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime());

    const groups: { [date: string]: Incident[] } = {};
    filtered.forEach(inc => {
      const dateKey = formatSimpleDate(inc.startTime);
      if (!groups[dateKey]) groups[dateKey] = [];
      groups[dateKey].push(inc);
    });

    return groups;
  }, [state.incidents, state.timezoneOffset]);

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <div className={`${globalStatus.color} rounded-xl p-8 text-white shadow-lg mb-8 transition-all duration-500`}>
        <div className="flex flex-col md:flex-row justify-between items-center gap-6">
          <div>
            <h1 className="text-3xl font-bold mb-2">{globalStatus.label}</h1>
            <p className="opacity-90">{globalStatus.sub}</p>
          </div>
          <div className="bg-white/10 p-4 rounded-xl backdrop-blur-md border border-white/20 w-full md:w-auto">
            <h3 className="text-sm font-bold mb-2 uppercase tracking-tighter">Get Status Updates</h3>
            <form onSubmit={(e) => handleSubscribe(e)} className="flex flex-col gap-2">
              <div className="flex bg-white rounded-lg overflow-hidden border border-white/30">
                <input 
                  type="email" 
                  required
                  placeholder="email@example.com" 
                  className="px-3 py-2 text-gray-900 text-xs outline-none w-full"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                />
                <button 
                  disabled={subStatus === 'loading'}
                  className="bg-indigo-600 px-4 py-2 text-xs font-bold hover:bg-indigo-700 transition-colors disabled:bg-indigo-400"
                >
                  {subStatus === 'loading' ? '...' : 'Subscribe'}
                </button>
              </div>
              <div className="flex justify-between items-center px-1">
                <button 
                  type="button"
                  onClick={(e) => handleSubscribe(e as any, true)}
                  className="text-[9px] font-bold uppercase hover:underline opacity-80"
                >
                  Unsubscribe
                </button>
                {subStatus === 'success' && <span className="text-[10px] font-bold text-emerald-300">Done!</span>}
                {subStatus === 'error' && <span className="text-[10px] font-bold text-red-300 truncate max-w-[150px]">{errorMessage}</span>}
              </div>
            </form>
          </div>
        </div>
      </div>

      {state.incidents.filter(i => !i.endTime).length > 0 && (
        <div className="mb-12">
          <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></span>
            Active Incidents
          </h2>
          <div className="space-y-4">
            {state.incidents.filter(i => !i.endTime).map(incident => (
              <div key={incident.id} className="bg-white border-l-4 border-red-500 rounded-lg p-6 shadow-sm animate-in fade-in slide-in-from-top-2">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-lg">{incident.title}</h3>
                  <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                    incident.severity === Severity.OUTAGE ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700'
                  }`}>
                    {incident.severity}
                  </span>
                </div>
                <p className="text-gray-600 mb-4">{incident.description}</p>
                <div className="text-xs text-gray-400">
                  Detected: {formatDate(incident.startTime)}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Current System Status */}
      <div className="space-y-12 mb-16">
        {state.regions.map(region => (
          <div key={region.id}>
            <h2 className="text-xs font-bold text-gray-400 uppercase tracking-[0.2em] mb-6 border-b pb-2">{region.name}</h2>
            <div className="space-y-8">
              {state.services.filter(s => s.regionId === region.id).map(service => {
                const serviceStatus = getServiceStatus(service.id);
                return (
                  <div key={service.id} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                    <div className="p-4 bg-gray-50 flex justify-between items-center border-b border-gray-100">
                      <div>
                        <h3 className="font-bold text-gray-700">{service.name}</h3>
                        <p className="text-[10px] text-gray-400 uppercase font-bold">{service.description}</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <span className={`text-xs font-bold uppercase ${
                          serviceStatus === Severity.OPERATIONAL ? 'text-emerald-500' :
                          serviceStatus === Severity.DEGRADED ? 'text-yellow-600' : 'text-red-600'
                        }`}>
                          {serviceStatus}
                        </span>
                        <div className={`w-2 h-2 rounded-full ${
                          serviceStatus === Severity.OPERATIONAL ? 'bg-emerald-500' :
                          serviceStatus === Severity.DEGRADED ? 'bg-yellow-500' : 'bg-red-500'
                        }`}></div>
                      </div>
                    </div>
                    <div className="divide-y divide-gray-50">
                      {state.components.filter(c => c.serviceId === service.id).map(comp => {
                        const compStatus = getComponentStatus(comp.id);
                        const sla = calculateSLA(comp.id);
                        return (
                          <div key={comp.id} className="p-6 hover:bg-gray-50 transition-colors">
                            <div className="flex justify-between items-center mb-3">
                              <div>
                                <h4 className="font-semibold text-gray-800 text-sm flex items-center gap-2">
                                  {comp.name}
                                  <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${sla < 99.9 ? 'bg-red-50 text-red-600' : 'bg-gray-100 text-gray-500'}`}>
                                    90D SLA: {sla}%
                                  </span>
                                </h4>
                                <p className="text-[10px] text-gray-400">{comp.description}</p>
                              </div>
                              <div className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${
                                compStatus === Severity.OPERATIONAL ? 'bg-emerald-50 text-emerald-600' :
                                compStatus === Severity.DEGRADED ? 'bg-yellow-50 text-yellow-600' : 'bg-red-50 text-red-600'
                              }`}>
                                {compStatus}
                              </div>
                            </div>
                            <UptimeGraph componentId={comp.id} createdAt={comp.createdAt} />
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ))}
      </div>

      {/* Past Incidents Section */}
      <div className="mt-20">
        <h2 className="text-2xl font-bold text-gray-900 mb-8 border-b pb-4">Incident History (Past 90 Days)</h2>

        {Object.keys(pastIncidentsByDate).length > 0 ? (
          <div className="space-y-10">
            {Object.entries(pastIncidentsByDate).map(([date, incidents]) => (
              <div key={date}>
                <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-4">{date}</h3>
                <div className="space-y-4">
                  {incidents.map(incident => {
                    const comp = state.components.find(c => c.id === incident.componentId);
                    const svc = state.services.find(s => s.id === comp?.serviceId);
                    const region = state.regions.find(r => r.id === svc?.regionId);

                    return (
                      <div key={incident.id} className="bg-white border border-gray-100 rounded-xl p-6 shadow-sm">
                        <div className="flex justify-between items-start mb-3">
                          <div>
                            <h4 className="font-bold text-gray-800">{incident.title}</h4>
                            <div className="flex items-center gap-2 mt-1">
                              <span className="text-[10px] text-indigo-600 font-bold uppercase tracking-tight">Component: {comp?.name || 'Unknown'}</span>
                              <span className="text-gray-300">•</span>
                              <span className="text-[10px] text-gray-500 font-bold uppercase tracking-tight">Region: {region?.name || 'Global'}</span>
                            </div>
                          </div>
                          <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded ${
                            incident.severity === Severity.OUTAGE ? 'bg-red-100 text-red-600' : 'bg-yellow-100 text-yellow-600'
                          }`}>
                            {incident.severity}
                          </span>
                        </div>
                        <p className="text-sm text-gray-600 mb-4">{incident.description}</p>
                        <div className="flex gap-4 text-[10px] font-medium text-gray-400 border-t pt-3">
                          <span className="flex items-center gap-1">
                            <span className="w-1.5 h-1.5 rounded-full bg-gray-300"></span>
                            Started: {formatDate(incident.startTime)}
                          </span>
                          {incident.endTime ? (
                            <span className="flex items-center gap-1">
                              <span className="w-1.5 h-1.5 rounded-full bg-emerald-300"></span>
                              Resolved: {formatDate(incident.endTime)}
                            </span>
                          ) : (
                            <span className="flex items-center gap-1">
                              <span className="w-1.5 h-1.5 rounded-full bg-red-400 animate-pulse"></span>
                              Ongoing
                            </span>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="bg-white border border-gray-100 rounded-xl p-12 text-center">
            <div className="w-16 h-16 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path>
              </svg>
            </div>
            <h3 className="text-lg font-bold text-gray-800 mb-1">No incidents reported</h3>
            <p className="text-gray-500 text-sm">All systems were operational during the past 90 days.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default PublicDashboard;

import React, { useState, useMemo } from 'react';
import { useApp } from '../../store.tsx';
import { Severity, Incident } from '../../types.ts';
import { geminiService } from '../../services/geminiService.ts';

const ReportingTab: React.FC = () => {
  const { state, reportIncident, updateIncident, resolveIncident, addTemplate } = useApp();
  const [isProcessing, setIsProcessing] = useState(false);
  const [isAiSuggesting, setIsAiSuggesting] = useState(false);
  const [editingIncident, setEditingIncident] = useState<Incident | null>(null);

  const initialForm = {
    regionId: '',
    serviceId: '',
    componentId: '',
    title: '',
    severity: Severity.DEGRADED,
    description: '',
    startTime: new Date().toISOString().slice(0, 16),
    endTime: '',
    saveAsTemplate: false,
    templateName: ''
  };

  const [form, setForm] = useState(initialForm);

  const activeIncidents = useMemo(() => state.incidents.filter(i => !i.endTime), [state.incidents]);
  const pastIncidents = useMemo(() => 
    state.incidents
      .filter(i => !!i.endTime)
      .sort((a, b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime())
      .slice(0, 10), 
    [state.incidents]
  );

  const filteredServices = useMemo(() => 
    state.services.filter(s => s.regionId === form.regionId), 
  [state.services, form.regionId]);

  const filteredComponents = useMemo(() => 
    state.components.filter(c => c.serviceId === form.serviceId), 
  [state.components, form.serviceId]);

  const availableTemplates = useMemo(() => {
    const comp = state.components.find(c => c.id === form.componentId);
    if (!comp) return [];
    return state.templates.filter(t => t.componentName === comp.name);
  }, [state.templates, form.componentId, state.components]);

  const handleEdit = (inc: Incident) => {
    const comp = state.components.find(c => c.id === inc.componentId);
    const svc = state.services.find(s => s.id === comp?.serviceId);

    setEditingIncident(inc);
    setForm({
      ...initialForm,
      regionId: svc?.regionId || '',
      serviceId: comp?.serviceId || '',
      componentId: inc.componentId,
      title: inc.title,
      severity: inc.severity,
      description: inc.description,
      startTime: inc.startTime.slice(0, 16),
      endTime: inc.endTime ? inc.endTime.slice(0, 16) : ''
    });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const applyTemplate = (templateId: string) => {
    const t = state.templates.find(x => x.id === templateId);
    if (t) {
      setForm(prev => ({ ...prev, title: t.title, description: t.description }));
    }
  };

  const handleCancelEdit = () => {
    setEditingIncident(null);
    setForm(initialForm);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.componentId) return alert('Please select a component.');
    setIsProcessing(true);
    try {
      const incidentPayload = {
        componentId: form.componentId,
        title: form.title,
        severity: form.severity,
        description: form.description,
        startTime: new Date(form.startTime).toISOString(),
        endTime: form.endTime ? new Date(form.endTime).toISOString() : null
      };

      if (editingIncident) {
        await updateIncident(editingIncident.id, incidentPayload);
      } else {
        await reportIncident(incidentPayload);

        if (form.saveAsTemplate && form.templateName) {
          const comp = state.components.find(c => c.id === form.componentId);
          if (comp) {
            await addTemplate({
              componentName: comp.name,
              name: form.templateName,
              title: form.title,
              description: form.description
            });
          }
        }
      }
      handleCancelEdit();
    } catch (err: any) {
      alert(`Operation failed: ${err.message}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleAiSuggest = async () => {
    if (!form.title || !form.description) return alert('Enter a title and description for AI to refine.');
    setIsAiSuggesting(true);
    try {
      const summary = await geminiService.generateIncidentSummary(form.title, form.description);
      setForm({ ...form, description: summary });
    } catch (err) {
      console.error('AI Suggestion error:', err);
    } finally {
      setIsAiSuggesting(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2 space-y-8">
        {/* Creation/Edit Form */}
        <div className="bg-white p-8 rounded-2xl border border-gray-200 shadow-sm relative overflow-hidden">
          {isProcessing && <div className="absolute inset-0 bg-white/50 backdrop-blur-[1px] z-10 flex items-center justify-center font-bold text-indigo-600">Syncing...</div>}

          <div className="flex justify-between items-center mb-8">
            <div>
              <h2 className="text-xl font-bold text-gray-900">{editingIncident ? 'Modify Incident Record' : 'Post New Update'}</h2>
              <p className="text-sm text-gray-400 mt-1">Updates are published to the public dashboard instantly.</p>
            </div>
            <div className="flex gap-2">
              {editingIncident && (
                <button onClick={handleCancelEdit} className="text-xs font-bold text-gray-400 hover:text-gray-600 uppercase px-3 py-1.5">
                  Cancel
                </button>
              )}
              <button 
                onClick={handleAiSuggest} 
                disabled={isAiSuggesting} 
                className={`text-xs font-bold px-4 py-2 rounded-xl transition-all border ${
                  isAiSuggesting ? 'bg-gray-50 text-gray-400 border-gray-100' : 'bg-indigo-50 text-indigo-600 border-indigo-100 hover:bg-indigo-100'
                }`}
              >
                {isAiSuggesting ? 'Processing...' : 'Gemini AI Summary'}
              </button>
            </div>
          </div>

          <form onSubmit={handleSave} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Location</label>
                <select 
                  required
                  className="w-full bg-gray-50 border border-gray-100 p-3 rounded-xl outline-none text-sm font-medium"
                  value={form.regionId}
                  onChange={e => setForm({...form, regionId: e.target.value, serviceId: '', componentId: ''})}
                >
                  <option value="">Region...</option>
                  {state.regions.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Functional Area</label>
                <select 
                  required
                  disabled={!form.regionId}
                  className="w-full bg-gray-50 border border-gray-100 p-3 rounded-xl outline-none text-sm font-medium disabled:opacity-50"
                  value={form.serviceId}
                  onChange={e => setForm({...form, serviceId: e.target.value, componentId: ''})}
                >
                  <option value="">Service...</option>
                  {filteredServices.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Impacted Component</label>
                <select 
                  required
                  disabled={!form.serviceId}
                  className="w-full bg-gray-50 border border-gray-100 p-3 rounded-xl outline-none text-sm font-medium disabled:opacity-50"
                  value={form.componentId}
                  onChange={e => setForm({...form, componentId: e.target.value})}
                >
                  <option value="">Component...</option>
                  {filteredComponents.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </div>
            </div>

            {availableTemplates.length > 0 && (
              <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 flex flex-col md:flex-row md:items-center justify-between gap-3">
                <div className="flex flex-col">
                  <span className="text-[10px] font-black text-indigo-600 uppercase">Load Macro</span>
                  <span className="text-[10px] text-indigo-400">Apply a pre-defined incident template</span>
                </div>
                <select 
                  className="text-xs border border-indigo-200 rounded-lg px-3 py-1.5 bg-white outline-none font-bold"
                  onChange={e => applyTemplate(e.target.value)}
                  defaultValue=""
                >
                  <option value="">Select template...</option>
                  {availableTemplates.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                </select>
              </div>
            )}

            <div className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Urgency</label>
                  <select 
                    className="w-full bg-gray-50 border border-gray-100 p-3.5 rounded-xl outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white transition-all text-sm font-bold"
                    value={form.severity}
                    onChange={e => setForm({...form, severity: e.target.value as Severity})}
                  >
                    <option value={Severity.DEGRADED}>🟡 Service Degradation</option>
                    <option value={Severity.OUTAGE}>🔴 Partial/Major Outage</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Headline</label>
                  <input 
                    required
                    placeholder="Public headline"
                    className="w-full bg-gray-50 border border-gray-100 p-3.5 rounded-xl outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white transition-all text-sm font-bold"
                    value={form.title}
                    onChange={e => setForm({...form, title: e.target.value})}
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Public Update Message</label>
                <textarea 
                  required
                  placeholder="Detailed description of the issue..."
                  rows={5}
                  className="w-full bg-gray-50 border border-gray-100 p-4 rounded-xl outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white transition-all text-sm leading-relaxed"
                  value={form.description}
                  onChange={e => setForm({...form, description: e.target.value})}
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Incident Start</label>
                  <input 
                    type="datetime-local" 
                    required
                    className="w-full bg-gray-50 border border-gray-100 p-3 rounded-xl text-xs font-semibold outline-none focus:bg-white"
                    value={form.startTime}
                    onChange={e => setForm({...form, startTime: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Resolved At (optional)</label>
                  <input 
                    type="datetime-local" 
                    className="w-full bg-gray-50 border border-gray-100 p-3 rounded-xl text-xs font-semibold outline-none focus:bg-white"
                    value={form.endTime}
                    onChange={e => setForm({...form, endTime: e.target.value})}
                  />
                </div>
              </div>

              {!editingIncident && (
                <div className="bg-gray-50 p-4 rounded-xl border border-gray-100 space-y-3">
                  <label className="flex items-center gap-3 cursor-pointer">
                    <input 
                      type="checkbox" 
                      className="w-4 h-4 rounded text-indigo-600 focus:ring-indigo-500"
                      checked={form.saveAsTemplate}
                      onChange={e => setForm({...form, saveAsTemplate: e.target.checked})}
                    />
                    <span className="text-xs font-bold text-gray-600">Save this response as a template for future use</span>
                  </label>
                  {form.saveAsTemplate && (
                    <input 
                      required
                      placeholder="Template internal name"
                      className="w-full bg-white border border-gray-200 p-2.5 rounded-lg text-xs outline-none focus:border-indigo-500"
                      value={form.templateName}
                      onChange={e => setForm({...form, templateName: e.target.value})}
                    />
                  )}
                </div>
              )}
            </div>

            <button type="submit" className="w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl hover:bg-indigo-700 shadow-xl shadow-indigo-600/20 transition-all">
              {editingIncident ? 'Save Changes' : 'Publish Status Update'}
            </button>
          </form>
        </div>

        {/* Enhanced Past History List */}
        <div className="space-y-4">
          <div className="flex justify-between items-end px-1">
            <h3 className="font-bold text-xs uppercase text-gray-400 tracking-widest">Incident History (Resolved)</h3>
            <span className="text-[10px] text-gray-300 font-bold">Showing last 10 entries</span>
          </div>

          <div className="grid grid-cols-1 gap-3">
            {pastIncidents.length > 0 ? (
              pastIncidents.map(inc => {
                const comp = state.components.find(c => c.id === inc.componentId);
                const svc = state.services.find(s => s.id === comp?.serviceId);
                const reg = state.regions.find(r => r.id === svc?.regionId);

                return (
                  <div key={inc.id} className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm flex flex-col md:flex-row md:items-center justify-between gap-4 group hover:border-indigo-200 transition-all">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[9px] font-bold text-gray-400 uppercase">{new Date(inc.startTime).toLocaleDateString()}</span>
                        <span className="text-gray-200">•</span>
                        <span className="text-[9px] font-black text-indigo-600 uppercase tracking-tighter">{reg?.name} / {comp?.name}</span>
                      </div>
                      <h4 className="text-sm font-bold text-gray-800 line-clamp-1">{inc.title}</h4>
                    </div>
                    <div className="flex items-center gap-4">
                      <div className="text-right hidden md:block">
                        <p className="text-[9px] font-bold text-gray-400 uppercase">Duration</p>
                        <p className="text-[10px] font-bold text-gray-600">
                          {Math.round((new Date(inc.endTime!).getTime() - new Date(inc.startTime).getTime()) / 60000)} mins
                        </p>
                      </div>
                      <button 
                        onClick={() => handleEdit(inc)} 
                        className="bg-gray-50 text-indigo-600 hover:bg-indigo-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-bold transition-all border border-indigo-50"
                      >
                        EDIT RECORD
                      </button>
                    </div>
                  </div>
                );
              })
            ) : (
              <div className="p-12 text-center bg-gray-50 rounded-2xl border border-dashed border-gray-200">
                <p className="text-gray-400 text-xs italic font-medium">No historical incidents recorded yet.</p>
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="space-y-6">
        <div className="bg-indigo-900 rounded-2xl p-6 text-white shadow-xl">
          <h3 className="text-xs font-black uppercase tracking-widest mb-4 opacity-50">Monitoring Stats</h3>
          <div className="space-y-5">
            <div className="flex justify-between items-center">
              <span className="text-xs font-bold text-indigo-200">Active Issues</span>
              <span className={`px-2 py-0.5 rounded-lg text-[10px] font-black ${activeIncidents.length > 0 ? 'bg-red-500 shadow-lg shadow-red-500/30' : 'bg-white/10'}`}>
                {activeIncidents.length}
              </span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-xs font-bold text-indigo-200">Historical Total</span>
              <span className="px-2 py-0.5 rounded-lg text-[10px] font-black bg-white/10">
                {state.incidents.length}
              </span>
            </div>
            <div className="pt-2 border-t border-white/10">
              <p className="text-[9px] font-bold text-indigo-300 uppercase mb-2">Platform Health</p>
              <div className="w-full bg-white/10 h-1.5 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-emerald-400 transition-all duration-1000" 
                  style={{ width: `${Math.max(20, 100 - (activeIncidents.length * 20))}%` }}
                ></div>
              </div>
            </div>
          </div>
        </div>

        <div className="space-y-4">
          <h3 className="font-bold text-xs uppercase text-gray-400 tracking-widest px-1">Currently Active</h3>
          {activeIncidents.length > 0 ? (
            activeIncidents.map(inc => (
              <div key={inc.id} className="p-5 bg-white border-2 border-red-50 rounded-2xl shadow-sm hover:border-red-100 transition-all">
                <div className="flex justify-between items-start mb-3">
                  <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-full ${
                    inc.severity === Severity.OUTAGE ? 'bg-red-500 text-white' : 'bg-yellow-400 text-yellow-900'
                  }`}>
                    {inc.severity}
                  </span>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => resolveIncident(inc.id)} 
                      className="text-[10px] font-bold text-emerald-600 hover:bg-emerald-50 px-2 py-1 rounded-lg"
                    >
                      RESOLVE
                    </button>
                    <button 
                      onClick={() => handleEdit(inc)} 
                      className="text-[10px] font-bold text-indigo-600 hover:bg-indigo-50 px-2 py-1 rounded-lg"
                    >
                      EDIT
                    </button>
                  </div>
                </div>
                <h4 className="text-sm font-bold text-gray-800 leading-snug mb-2">{inc.title}</h4>
                <p className="text-[9px] text-gray-400 font-bold uppercase">Time elapsed: {Math.round((Date.now() - new Date(inc.startTime).getTime()) / 60000)} mins</p>
              </div>
            ))
          ) : (
            <div className="p-8 text-center bg-emerald-50 rounded-2xl border border-dashed border-emerald-100">
              <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center mx-auto mb-3 text-emerald-500 shadow-sm">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
              </div>
              <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Normal Operations</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ReportingTab;

import React, { useState } from 'react';
import { useApp } from '../../store.tsx';

const ConfigurationTab: React.FC = () => {
  const { state, addRegion, removeRegion, addService, removeService, addComponent, removeComponent } = useApp();
  const [activeForm, setActiveForm] = useState<'region' | 'service' | 'component' | null>(null);
  const [formState, setFormState] = useState({ name: '', description: '', parentId: '' });

  const handleAddInfrastructure = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formState.name) return;

    try {
      if (activeForm === 'region') {
        await addRegion(formState.name);
      } else if (activeForm === 'service') {
        await addService(formState.parentId, formState.name, formState.description);
      } else if (activeForm === 'component') {
        await addComponent(formState.parentId, formState.name, formState.description);
      }
      setActiveForm(null);
      setFormState({ name: '', description: '', parentId: '' });
    } catch (err) {
      alert("Creation failed. Please try again.");
    }
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-xl font-bold text-gray-900">Infrastructure Mapping</h2>
          <p className="text-sm text-gray-400 mt-1">Define regions, functional services, and underlying components.</p>
        </div>
        <button 
          onClick={() => { setFormState({ name: '', description: '', parentId: '' }); setActiveForm('region'); }}
          className="bg-indigo-600 text-white px-6 py-3 rounded-xl text-sm font-bold shadow-lg shadow-indigo-600/20 hover:bg-indigo-700 transition-all"
        >
          + Add Region
        </button>
      </div>

      <div className="grid grid-cols-1 gap-8">
        {state.regions.map(region => (
          <div key={region.id} className="bg-white border border-gray-100 rounded-3xl overflow-hidden shadow-sm hover:shadow-md transition-shadow">
            <div className="px-8 py-5 bg-gray-50/50 border-b border-gray-100 flex justify-between items-center">
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 bg-white rounded-lg border border-gray-100 flex items-center justify-center text-gray-400">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                </div>
                <h3 className="font-black text-gray-800 uppercase tracking-tight">{region.name}</h3>
              </div>
              <div className="flex gap-4">
                <button 
                  onClick={() => { setActiveForm('service'); setFormState({ name: '', description: '', parentId: region.id }); }}
                  className="text-xs font-bold text-indigo-600 hover:underline uppercase tracking-tighter"
                >
                  Create Service
                </button>
                <button 
                  onClick={() => confirm(`Permanently remove ${region.name} and all associated services?`) && removeRegion(region.id)}
                  className="text-xs font-bold text-red-400 hover:text-red-600 uppercase tracking-tighter"
                >
                  Delete
                </button>
              </div>
            </div>

            <div className="p-8 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {state.services.filter(s => s.regionId === region.id).map(service => (
                <div key={service.id} className="border border-gray-100 rounded-2xl p-6 bg-gray-50/30 flex flex-col group">
                  <div className="flex justify-between items-start mb-2">
                    <span className="font-bold text-sm text-gray-800">{service.name}</span>
                    <button 
                      onClick={() => confirm(`Delete service ${service.name}?`) && removeService(service.id)}
                      className="text-[10px] text-red-400 font-bold uppercase opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      Remove
                    </button>
                  </div>
                  <p className="text-[10px] text-gray-400 font-medium mb-4 italic line-clamp-1">{service.description || 'No description provided.'}</p>

                  <div className="space-y-2 flex-1">
                    {state.components.filter(c => c.serviceId === service.id).map(comp => (
                      <div key={comp.id} className="flex flex-col bg-white p-3 rounded-xl border border-gray-100 shadow-sm relative group/comp">
                        <div className="flex justify-between items-center mb-0.5">
                          <span className="text-xs font-bold text-gray-700">{comp.name}</span>
                          <button 
                            onClick={() => confirm(`Delete component ${comp.name}?`) && removeComponent(comp.id)}
                            className="text-red-300 hover:text-red-500 text-lg leading-none opacity-0 group-hover/comp:opacity-100 transition-opacity"
                          >
                            ×
                          </button>
                        </div>
                        {comp.description && <p className="text-[9px] text-gray-400 line-clamp-1">{comp.description}</p>}
                      </div>
                    ))}
                    <button 
                      onClick={() => { setActiveForm('component'); setFormState({ name: '', description: '', parentId: service.id }); }}
                      className="w-full py-2.5 border border-dashed border-indigo-100 rounded-xl text-[10px] font-black text-indigo-400 uppercase tracking-widest hover:bg-indigo-50 transition-colors mt-2"
                    >
                      + Component
                    </button>
                  </div>
                </div>
              ))}

              {state.services.filter(s => s.regionId === region.id).length === 0 && (
                <div className="col-span-full py-12 text-center border-2 border-dashed border-gray-100 rounded-2xl">
                  <p className="text-xs text-gray-300 font-bold uppercase tracking-widest">No services defined for this region</p>
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {activeForm && (
        <div className="fixed inset-0 bg-gray-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <form onSubmit={handleAddInfrastructure} className="bg-white p-8 rounded-3xl shadow-2xl w-full max-w-md animate-in zoom-in-95">
            <h3 className="font-black text-xl mb-6 text-gray-900 flex items-center gap-3">
              <span className="w-2 h-6 bg-indigo-600 rounded-full"></span>
              Create {activeForm.charAt(0).toUpperCase() + activeForm.slice(1)}
            </h3>

            <div className="space-y-4 mb-8">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Display Name</label>
                <input 
                  autoFocus
                  required
                  className="w-full bg-gray-50 border border-gray-100 p-3.5 rounded-xl outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white transition-all text-sm font-bold"
                  placeholder={`e.g. ${activeForm === 'region' ? 'Frankfurt (EU-Central)' : activeForm === 'service' ? 'Real-time Messaging' : 'PostgreSQL Master'}`}
                  value={formState.name}
                  onChange={e => setFormState({ ...formState, name: e.target.value })}
                />
              </div>

              {(activeForm === 'service' || activeForm === 'component') && (
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest px-1">Internal Description</label>
                  <textarea 
                    rows={3}
                    className="w-full bg-gray-50 border border-gray-100 p-3.5 rounded-xl outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white transition-all text-sm leading-relaxed"
                    placeholder="Briefly describe the purpose of this resource..."
                    value={formState.description}
                    onChange={e => setFormState({ ...formState, description: e.target.value })}
                  />
                </div>
              )}
            </div>

            <div className="flex gap-3">
              <button 
                type="submit"
                className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-600/20 hover:bg-indigo-700 transition-all"
              >
                Confirm Creation
              </button>
              <button 
                type="button"
                onClick={() => setActiveForm(null)}
                className="px-6 py-4 text-gray-400 font-bold text-sm hover:text-gray-600"
              >
                Cancel
              </button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

